 50 |     fun loadFolderCache(context: android.content.Context) {
 51 |         val file = File(context.filesDir, "folder_counts.json")
 52 |         if (file.exists()) {
 53 |             try {
 54 |                 val json = org.json.JSONObject(file.readText())
 55 |                 json.keys().forEach { path ->
 56 |                     val data = json.getJSONArray(path)
 57 |                     folderCountCache[path] = data.getLong(0) to data.getInt(1)
 58 |                 }
 59 |             } catch(e: Exception) {}
 60 |         }
 61 |     }
