343 |     fun loadExplorerFolder(context: android.content.Context, path: String) {
344 |         if (explorerCategory != "Internal Storage" && explorerCategory != null) {
345 |             explorerReturnCategory = explorerCategory
346 |         }
347 |         explorerCategory = "Internal Storage"
348 |         explorerPath = path
349 |         isScanningExplorer = true
350 |         viewModelScope.launch(Dispatchers.IO) {
351 |             val rawResults = if (path.contains("!/")) {
352 |                 val zipPath = path.substringBefore("!/")
353 |                 val internal = path.substringAfter("!/")
354 |                 FileScanner.getZipContents(zipPath, internal)
355 |             } else {
356 |                 val results = FileScanner.getDirectoryContents(path, currentSortOrder, folderCountCache)
357 |                 // Save cache if it was updated during the scan
358 |                 saveFolderCache(context)
359 |                 results
360 |             }
361 |             val sortedResults = rawResults.sortedByDescending { it.path in pinnedPaths }
362 |             withContext(Dispatchers.Main) {
363 |                 explorerFiles = sortedResults
364 |                 isScanningExplorer = false
365 |             }
366 |         }
367 |     }
