369 |     fun openExplorerCategory(context: android.content.Context, cat: String) {
370 |         explorerCategory = cat
371 |         isScanningExplorer = true
372 |         viewModelScope.launch(Dispatchers.IO) {
373 |             val results = when (cat) {
374 |                 "Recent Files" -> FileScanner.getRecentFiles(context)
375 |                 "Images", "Videos", "Audio" -> FileScanner.getMediaFiles(context, cat)
376 |                 "Internal Storage" -> {
377 |                     explorerPath = "/storage/emulated/0"
378 |                     FileScanner.getDirectoryContents(explorerPath, currentSortOrder)
379 |                 }
380 |                 "Downloads" -> {
381 |                     explorerPath = "/storage/emulated/0/Download"
382 |                     FileScanner.getDirectoryContents(explorerPath, currentSortOrder)
383 |                 }
384 |                 else -> {
385 |                     val python = com.chaquo.python.Python.getInstance()
386 |                     val executor = python.getModule("executor")
387 |                     val list = executor.callAttr("find_files_by_type", cat.lowercase()).asList()
388 |                     list.map { 
389 |                         val p = it.toString()
390 |                         val f = File(p)
391 |                         val sizeStr = if (f.length() > 0) {
392 |                             val bytes = f.length()
393 |                             val units = arrayOf("B", "KB", "MB", "GB")
394 |                             val i = (Math.log10(bytes.toDouble()) / Math.log10(1024.0)).toInt()
395 |                             String.format("%.1f %s", bytes / Math.pow(1024.0, i.toDouble()), units[i])
396 |                         } else "0 B"
397 |                         
398 |                         val parentFolder = p.split("/").dropLast(1).lastOrNull() ?: ""
399 |                         
400 |                         FileItem(
401 |                             name = f.name, 
402 |                             meta = "$sizeStr • $parentFolder", 
403 |                             icon = if (cat == "Zips") Icons.Default.Archive else Icons.Default.Description, 
404 |                             color = if (cat == "Zips") Color(0xFFFF4081) else Color(0xFFFFD740), 
405 |                             path = p
406 |                         )
407 |                     }
408 |                 }
409 |             }
410 |             withContext(Dispatchers.Main) {
411 |                 explorerFiles = results
412 |                 isScanningExplorer = false
413 |             }
414 |         }
415 |     }
