417 |     fun updateStorageStats() {
418 |         try {
419 |             val stat = android.os.StatFs(android.os.Environment.getExternalStorageDirectory().path)
420 |             val bytesTotal = stat.totalBytes
421 |             val bytesAvailable = stat.availableBytes
422 |             val bytesUsed = bytesTotal - bytesAvailable
423 | 
424 |             val totalGB = bytesTotal / (1024 * 1024 * 1024.0)
425 |             val usedGB = bytesUsed / (1024 * 1024 * 1024.0)
426 | 
427 |             storageLabel = "${String.format("%.1f", usedGB)} GB / ${String.format("%.1f", totalGB)} GB"
428 |             storagePercent = (usedGB.toFloat() / totalGB.toFloat())
429 |         } catch (e: Exception) {
430 |             storageLabel = "Error reading storage"
431 |         }
432 |     }
