476 |     fun sendMessage(context: android.content.Context, displayAsSystem: Boolean = false) {
477 |         if (aiStatus != null) return // Prevent concurrent calls
478 |         val text = chatInput
479 |         if (text.isBlank() && stagedFiles.isEmpty()) return
480 | 
481 |         val selectionContext = if (selectedFiles.isNotEmpty()) {
482 |             "[User has selected: ${selectedFiles.joinToString { it.path }}]\n"
483 |         } else ""
484 |         
485 |         val finalPrompt = if (stagedFiles.isNotEmpty()) {
486 |             "$selectionContext[Attached Files: ${stagedFiles.joinToString { it.absolutePath }}]\n\n$text"
487 |         } else "$selectionContext$text"
488 | 
489 |         chatInput = ""
490 |         stagedFiles = emptyList()
491 | 
492 |         viewModelScope.launch {
493 |             aiStatus = "Thinking..."
494 |             
495 |             val localTimestamp = java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", java.util.Locale.US).apply {
496 |                 timeZone = java.util.TimeZone.getTimeZone("UTC")
497 |             }.format(java.util.Date())
498 | 
499 |             val userMsg = Message(
500 |                 id = System.currentTimeMillis(), 
501 |                 sender = "User", 
502 |                 text = if (displayAsSystem) "[System Action]" else finalPrompt, 
503 |                 isAi = false, 
504 |                 isSystemAction = displayAsSystem, 
505 |                 timestamp = localTimestamp
506 |             )
507 | 
508 |             if (editingMessageTimestamp != null && currentSessionId != null) {
509 |                 val msgIndex = chatMessages.indexOfFirst { it.timestamp == editingMessageTimestamp }
510 |                 if (msgIndex != -1) {
511 |                     val tsToMatch = editingMessageTimestamp!!
512 |                     
513 |                     // Sequential sync: Try to kill the backend branch before updating local UI
514 |                     val success = withContext(Dispatchers.IO) {
515 |                         SupabaseClient.truncateHistory(currentSessionId!!, tsToMatch)
516 |                     }
517 |                     
518 |                     if (success) {
519 |                         chatMessages = chatMessages.take(msgIndex) + userMsg
520 |                     } else {
521 |                         withContext(Dispatchers.Main) {
522 |                             android.widget.Toast.makeText(context, "Failed to sync edit with server. History intact.", android.widget.Toast.LENGTH_LONG).show()
523 |                         }
524 |                         // Still send the message so the user isn't blocked, but we don't truncate locally to match the server desync
525 |                         chatMessages = chatMessages + userMsg 
526 |                     }
527 |                 } else {
528 |                     chatMessages = chatMessages + userMsg
529 |                 }
530 |                 editingMessageTimestamp = null
531 |             } else {
532 |                 chatMessages = chatMessages + userMsg
533 |             }
534 | 
535 |             if (currentSessionId == null) {
536 |                 val cleanText = text.trim()
537 |                 val fallbackTitle = if (cleanText.isNotBlank()) {
538 |                     if (cleanText.length > 30) cleanText.take(30) + "..." else cleanText
539 |                 } else if (finalPrompt.contains("[Attached Files:")) {
540 |                     "File Analysis"
541 |                 } else {
542 |                     "New Conversation"
543 |                 }
544 |                 val newId = SupabaseClient.createNewSessionInSupabase(fallbackTitle)
545 |                 currentSessionId = newId
546 |                 refreshSessions()
547 |             }
548 |             
549 |             val aiResponse = SupabaseClient.callGeminiEdgeFunction(context, finalPrompt, currentSessionId) { status ->
550 |                 viewModelScope.launch(Dispatchers.Main) {
551 |                     if (status.contains("[PROGRESS:")) {
552 |                         val regex = "\\[PROGRESS:(\\d+):(.*)\\]".toRegex()
553 |                         regex.find(status)?.let { match ->
554 |                             val (p, s) = match.destructured
555 |                             scriptProgress = p.toFloat() / 100f
556 |                             aiStatus = "Executing: $s"
557 |                         }
558 |                     } else {
559 |                         aiStatus = status
560 |                     }
561 |                 }
562 |             }
563 |             
564 |             // Check for UI Navigation commands in the response
565 |             try {
566 |                 if (aiResponse.startsWith("[")) {
567 |                     val blocks = org.json.JSONArray(aiResponse)
568 |                     for (i in 0 until blocks.length()) {
569 |                         val block = blocks.getJSONObject(i)
570 |                         if (block.optString("type") == "batch_op") {
571 |                             val op = block.getString("operation")
572 |                             val paths = block.getJSONArray("paths")
573 |                             val dest = block.optString("destination")
574 |                             
575 |                             viewModelScope.launch(Dispatchers.IO) {
576 |                                 for (i in 0 until paths.length()) {
577 |                                     val f = File(paths.getString(i))
578 |                                     if (op == "delete") {
579 |                                         if (f.isDirectory) f.deleteRecursively() else f.delete()
580 |                                     } else if (op == "move" && dest.isNotEmpty()) {
581 |                                         val target = File(dest, f.name)
582 |                                         f.renameTo(target)
583 |                                     }
584 |                                 }
585 |                                 withContext(Dispatchers.Main) {
586 |                                     loadExplorerFolder(explorerPath)
587 |                                     android.widget.Toast.makeText(context, "Batch $op complete", android.widget.Toast.LENGTH_SHORT).show()
588 |                                 }
