419 |     fun updateStorageStats() {
420 |         try {
421 |             val stat = android.os.StatFs(android.os.Environment.getExternalStorageDirectory().path)
422 |             val bytesTotal = stat.totalBytes
423 |             val bytesAvailable = stat.availableBytes
424 |             val bytesUsed = bytesTotal - bytesAvailable
425 | 
426 |             val totalGB = bytesTotal / (1024 * 1024 * 1024.0)
427 |             val usedGB = bytesUsed / (1024 * 1024 * 1024.0)
428 | 
429 |             storageLabel = "${String.format("%.1f", usedGB)} GB / ${String.format("%.1f", totalGB)} GB"
430 |             storagePercent = (usedGB.toFloat() / totalGB.toFloat())
431 |         } catch (e: Exception) {
432 |             storageLabel = "Error reading storage"
433 |         }
434 |     }
