478 |     fun sendMessage(context: android.content.Context, displayAsSystem: Boolean = false) {
479 |         if (aiStatus != null) return // Prevent concurrent calls
480 |         val text = chatInput
481 |         if (text.isBlank() && stagedFiles.isEmpty()) return
482 | 
483 |         val selectionContext = if (selectedFiles.isNotEmpty()) {
484 |             "[User has selected: ${selectedFiles.joinToString { it.path }}]\n"
485 |         } else ""
486 |         
487 |         val finalPrompt = if (stagedFiles.isNotEmpty()) {
488 |             "$selectionContext[Attached Files: ${stagedFiles.joinToString { it.absolutePath }}]\n\n$text"
489 |         } else "$selectionContext$text"
490 | 
491 |         chatInput = ""
492 |         stagedFiles = emptyList()
493 | 
494 |         viewModelScope.launch {
495 |             aiStatus = "Thinking..."
496 |             
497 |             val localTimestamp = java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", java.util.Locale.US).apply {
498 |                 timeZone = java.util.TimeZone.getTimeZone("UTC")
499 |             }.format(java.util.Date())
500 | 
501 |             val userMsg = Message(
502 |                 id = System.currentTimeMillis(), 
503 |                 sender = "User", 
504 |                 text = if (displayAsSystem) "[System Action]" else finalPrompt, 
505 |                 isAi = false, 
506 |                 isSystemAction = displayAsSystem, 
507 |                 timestamp = localTimestamp
508 |             )
509 | 
510 |             if (editingMessageTimestamp != null && currentSessionId != null) {
511 |                 val msgIndex = chatMessages.indexOfFirst { it.timestamp == editingMessageTimestamp }
512 |                 if (msgIndex != -1) {
513 |                     val tsToMatch = editingMessageTimestamp!!
514 |                     
515 |                     // Sequential sync: Try to kill the backend branch before updating local UI
516 |                     val success = withContext(Dispatchers.IO) {
517 |                         SupabaseClient.truncateHistory(currentSessionId!!, tsToMatch)
518 |                     }
519 |                     
520 |                     if (success) {
521 |                         chatMessages = chatMessages.take(msgIndex) + userMsg
522 |                     } else {
523 |                         withContext(Dispatchers.Main) {
524 |                             android.widget.Toast.makeText(context, "Failed to sync edit with server. History intact.", android.widget.Toast.LENGTH_LONG).show()
525 |                         }
526 |                         // Still send the message so the user isn't blocked, but we don't truncate locally to match the server desync
527 |                         chatMessages = chatMessages + userMsg 
528 |                     }
529 |                 } else {
530 |                     chatMessages = chatMessages + userMsg
531 |                 }
532 |                 editingMessageTimestamp = null
533 |             } else {
534 |                 chatMessages = chatMessages + userMsg
535 |             }
536 | 
537 |             if (currentSessionId == null) {
538 |                 val cleanText = text.trim()
539 |                 val fallbackTitle = if (cleanText.isNotBlank()) {
540 |                     if (cleanText.length > 30) cleanText.take(30) + "..." else cleanText
541 |                 } else if (finalPrompt.contains("[Attached Files:")) {
542 |                     "File Analysis"
543 |                 } else {
544 |                     "New Conversation"
545 |                 }
546 |                 val newId = SupabaseClient.createNewSessionInSupabase(fallbackTitle)
547 |                 currentSessionId = newId
548 |                 refreshSessions()
549 |             }
550 |             
551 |             val aiResponse = SupabaseClient.callGeminiEdgeFunction(context, finalPrompt, currentSessionId) { status ->
552 |                 viewModelScope.launch(Dispatchers.Main) {
553 |                     if (status.contains("[PROGRESS:")) {
554 |                         val regex = "\\[PROGRESS:(\\d+):(.*)\\]".toRegex()
555 |                         regex.find(status)?.let { match ->
556 |                             val (p, s) = match.destructured
557 |                             scriptProgress = p.toFloat() / 100f
558 |                             aiStatus = "Executing: $s"
559 |                         }
560 |                     } else {
561 |                         aiStatus = status
562 |                     }
563 |                 }
564 |             }
565 |             
566 |             // Check for UI Navigation commands in the response
567 |             try {
568 |                 if (aiResponse.startsWith("[")) {
569 |                     val blocks = org.json.JSONArray(aiResponse)
570 |                     for (i in 0 until blocks.length()) {
571 |                         val block = blocks.getJSONObject(i)
572 |                         if (block.optString("type") == "batch_op") {
573 |                             val op = block.getString("operation")
574 |                             val paths = block.getJSONArray("paths")
575 |                             val dest = block.optString("destination")
576 |                             
577 |                             viewModelScope.launch(Dispatchers.IO) {
578 |                                 for (i in 0 until paths.length()) {
579 |                                     val f = File(paths.getString(i))
580 |                                     if (op == "delete") {
581 |                                         if (f.isDirectory) f.deleteRecursively() else f.delete()
582 |                                     } else if (op == "move" && dest.isNotEmpty()) {
583 |                                         val target = File(dest, f.name)
584 |                                         f.renameTo(target)
585 |                                     }
586 |                                 }
587 |                                 withContext(Dispatchers.Main) {
588 |                                     loadExplorerFolder(explorerPath)
589 |                                     android.widget.Toast.makeText(context, "Batch $op complete", android.widget.Toast.LENGTH_SHORT).show()
590 |                                 }
591 |                             }
592 |                         }
593 |                         if (block.optString("type") == "ui_nav") {
594 |                             val rawPath = block.getString("path")
595 |                             val mode = block.getString("mode")
596 |                             val file = java.io.File(rawPath).canonicalFile // Normalize the path
597 |                             
598 |                             if (file.exists()) {
599 |                                 if (mode == "direct" && file.isFile) {
600 |                                     openFileForEditing(file)
601 |                                     currentView = "explorer"
602 |                                     selectedTab = 1
603 |                                 } else {
604 |                                     // Mode 'location' - AI wants us to find the item in its folder
605 |                                     val targetPath = file.absolutePath
606 |                                     val parent = file.parent ?: "/storage/emulated/0"
607 |                                     
608 |                                     highlightedPath = targetPath
609 |                                     explorerCategory = "Internal Storage"
610 |                                     loadExplorerFolder(parent)
611 |                                     currentView = "explorer"
612 |                                     selectedTab = 1
613 |                                 }
614 |                             }
615 |                         }
616 |                     }
617 |                 }
618 |             } catch (e: Exception) { }
619 | 
620 |             chatMessages = chatMessages + Message(System.currentTimeMillis() + 1, "AI", aiResponse, true)
621 |             
622 |             val userMsgCount = chatMessages.count { !it.isAi && !it.isSystemAction }
623 |             if (userMsgCount == 3 || userMsgCount == 5) {
624 |                 viewModelScope.launch {
625 |                     SupabaseClient.generateTitleForSession(currentSessionId!!)
626 |                     refreshSessions()
627 |                 }
628 |             }
629 | 
630 |             syncCwd()
631 |             aiStatus = null
632 |         }
633 |     }
