758 |         // Handle Virtual Archive Paths Safely
759 |         if (fileItem.path.contains("!/")) {
760 |             if (fileItem.path.endsWith("/")) {
761 |                 explorerCategory = "Internal Storage"
762 |                 loadFolder(fileItem.path)
763 |             } else {
764 |                 val textExts = listOf(
765 |                     "txt", "py", "js", "json", "kt", "java", "html", "css", "md", "yml", "yaml", 
766 |                     "c", "cpp", "h", "ts", "tsx", "jsx", "xml", "sql", "log", "env", "ini", 
767 |                     "conf", "sh", "bat", "gradle", "properties", "toml"
768 |                 )
